# Implementation d'un solveur HTN simplifie
from dataclasses import dataclass, field
from typing import List, Dict, Set, Tuple, Optional, Any, Union
from copy import deepcopy

@dataclass
class State:
    """Representation d'un etat du monde."""
    facts: Set[Tuple[str, ...]]  # Ensemble de faits (predicats)

    def holds(self, predicate: Tuple[str, ...]) -> bool:
        """Verifie si un fait est vrai dans l'etat."""
        return predicate in self.facts

    def add(self, predicate: Tuple[str, ...]) -> 'State':
        """Ajoute un fait et retourne un nouvel etat."""
        new_facts = self.facts | {predicate}
        return State(new_facts)

    def remove(self, predicate: Tuple[str, ...]) -> 'State':
        """Retire un fait et retourne un nouvel etat."""
        new_facts = self.facts - {predicate}
        return State(new_facts)

    def __repr__(self):
        return f"State({sorted(self.facts)})"


@dataclass
class Action:
    """Action primitive avec preconditions et effets."""
    name: str
    parameters: List[str]
    preconditions: List[Tuple[str, ...]]
    add_effects: List[Tuple[str, ...]]
    del_effects: List[Tuple[str, ...]]

    def is_applicable(self, state: State, binding: Dict[str, str]) -> bool:
        """Verifie si l'action est applicable avec les bindings donnes."""
        for precond in self.preconditions:
            ground = tuple(binding.get(p, p) for p in precond)
            if not state.holds(ground):
                return False
        return True

    def apply(self, state: State, binding: Dict[str, str]) -> State:
        """Applique l'action et retourne le nouvel etat."""
        new_state = state
        for eff in self.del_effects:
            ground = tuple(binding.get(p, p) for p in eff)
            new_state = new_state.remove(ground)
        for eff in self.add_effects:
            ground = tuple(binding.get(p, p) for p in eff)
            new_state = new_state.add(ground)
        return new_state

    def ground(self, binding: Dict[str, str]) -> str:
        """Retourne la representation groundee de l'action."""
        params = [binding.get(p, p) for p in self.parameters]
        return f"{self.name}({', '.join(params)})"


@dataclass
class Method:
    """Methode de decomposition pour tache abstraite."""
    name: str
    task_name: str
    task_params: List[str]
    parameters: List[str]
    preconditions: List[Tuple[str, ...]]
    subtasks: List[Tuple[str, List[str]]]  # (nom_tache, params)

    def is_applicable(self, state: State, binding: Dict[str, str]) -> bool:
        """Verifie si la methode est applicable."""
        for precond in self.preconditions:
            ground = tuple(binding.get(p, p) for p in precond)
            if not state.holds(ground):
                return False
        return True

print("Classes de base definies: State, Action, Method")

@dataclass
class PlanningState:
    """Represente un etat de planification"""
    objects: Dict[str, List[str]]  # type -> liste d'objets
    predicates: List[str]  # faits vrais

@dataclass  
class Action:
    """Represente une action du plan"""
    name: str
    parameters: List[str]
    preconditions: List[str]
    effects: List[str]

def generate_plan_direct(
    goal: str,
    initial_state: PlanningState,
    available_actions: List[str],
    client_type: str = "anthropic"
) -> List[Action]:
    """
    Genere un plan directement via LLM
    """
    prompt = f"""Tu es un assistant de planification automatique.

ETAT INITIAL:
- Objets: {json.dumps(initial_state.objects, indent=2)}
- Faits vrais: {', '.join(initial_state.predicates)}

BUT A ATTEINDRE: {goal}

ACTIONS DISPONIBLES:
{chr(10).join(f'- {a}' for a in available_actions)}

Genere une sequence d'actions pour atteindre le but.
Format de sortie JSON:
[
  {{\"action\": \"nom\", \"params\": [\"param1\"], \"preconditions\": [\"cond1\"], \"effects\": [\"eff1\"]}}
]
"""

    if client_type == "anthropic" and anthropic_client:
        response = anthropic_client.messages.create(
            model=config.model_anthropic,
            max_tokens=config.max_tokens,
            messages=[{"role": "user", "content": prompt}]
        )
        content = response.content[0].text
    elif client_type == "openai" and openai_client:
        response = openai_client.chat.completions.create(
            model=config.model_openai,
            max_tokens=config.max_tokens,
            messages=[{"role": "user", "content": prompt}],
            extra_body={
        "chat_template_kwargs": {"enable_thinking": False}
    }
        )
        content = response.choices[0].message.content
    else:
        return []
    try:
        json_start = content.find('[')
        json_end = content.rfind(']') + 1
        if json_start != -1 and json_end > json_start:
            plan_data = json.loads(content[json_start:json_end])
            return [Action(
                name=a["action"],
                parameters=a.get("params", []),
                preconditions=a.get("preconditions", []),
                effects=a.get("effects", [])
            ) for a in plan_data]
    except json.JSONDecodeError as e:
        print(f"Erreur parsing JSON: {e}")

    return []

print(f"Classes definies : PlanningState, Action, generate_plan_direct")

def repair_plan(
    original_plan: List[Action],
    failure_point: int,
    failure_reason: str,
    current_state: PlanningState,
    goal: str
) -> List[Action]:
    """Repare un plan qui a echoue a une etape donnee"""
    executed_actions = original_plan[:failure_point]

    prompt = f"""Un plan a echoue. Aide a le reparer.

ACTIONS DEJA EXECUTEES:
{json.dumps([{'action': a.name, 'params': a.parameters} for a in executed_actions], indent=2)}

ECHEC a l'etape {failure_point}: {failure_reason}

ETAT ACTUEL: {current_state.predicates}
BUT RESTANT: {goal}

Propose un plan reparateur en JSON.
"""

    if anthropic_client:
        response = anthropic_client.messages.create(
            model=config.model_anthropic,
            max_tokens=config.max_tokens,
            messages=[{"role": "user", "content": prompt}]
        )
        return []

    return []

print("Fonction de plan repair definie")

def llm_heuristic(state: PlanningState, goal: str, scale: int = 10) -> float:
    """Utilise le LLM pour estimer la distance au but (0 = but atteint)"""
    prompt = f"""Note la proximite de cet etat au but.

ETAT: {', '.join(state.predicates)}
BUT: {goal}

Donne un score de 0 (but atteint) a {scale} (tres loin).
Reponds uniquement par le chiffre.
"""

    if anthropic_client:
        response = anthropic_client.messages.create(
            model=config.model_anthropic,
            max_tokens=10,
            messages=[{"role": "user", "content": prompt}]
        )
        try:
            score = float(response.content[0].text.strip())
            return min(max(score, 0), scale)
        except ValueError:
            return scale / 2

    return 5.0

print("Fonction heuristique LLM definie")

# Resolution avec un seul solveur (Pyperplan - leger et rapide)

def solve_with_planner(problem, planner_name='pyperplan', verbose=True):
    """Resout un probleme avec un planificateur donne."""
    start_time = time.time()

    try:
        with OneshotPlanner(name=planner_name) as planner:
            result = planner.solve(problem)

        solve_time = time.time() - start_time

        if verbose:
            print(f"\n{'='*50}")
            print(f"Solveur: {planner_name}")
            print(f"{'='*50}")
            print(f"Statut: {result.status.name}")
            print(f"Temps: {solve_time:.3f}s")

            if result.plan is not None:
                print(f"\nPlan trouve ({len(result.plan.actions)} actions):")
                for i, action in enumerate(result.plan.actions):
                    print(f"  {i+1}. {action}")
            else:
                print("Aucun plan trouve")

        return {
            'planner': planner_name,
            'status': result.status.name,
            'time': solve_time,
            'plan': result.plan,
            'plan_length': len(result.plan.actions) if result.plan else None
        }

    except Exception as e:
        if verbose:
            print(f"Erreur avec {planner_name}: {e}")
        return {
            'planner': planner_name,
            'status': 'ERROR',
            'time': time.time() - start_time,
            'plan': None,
            'plan_length': None,
            'error': str(e)
        }

